+function findOptionDependency(usage: Usage): OptionDependency | undefined {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn !== undefined) {
+      return term.dependsOn;
+    }
+    if (term.type === "optional" || term.type === "multiple") {
+      const dependency = findOptionDependency(term.terms);
+      if (dependency !== undefined) return dependency;
+    }
+  }
+  return undefined;
+}
+
+function findOptionNamesInUsage(usage: Usage): readonly string[] | undefined {
+  for (const term of usage) {
+    if (term.type === "option") return term.names;
+    if (term.type === "optional" || term.type === "multiple") {
+      const names = findOptionNamesInUsage(term.terms);
+      if (names !== undefined) return names;
+    }
+  }
+  return undefined;
+}
+
+function unwrapOptionState(state: unknown): { readonly present: boolean; readonly value: unknown } {
+  if (Array.isArray(state)) return state.length === 1
+    ? unwrapOptionState(state[0])
+    : { present: false, value: undefined };
+  if (state !== null && typeof state === "object" && "success" in state) {
+    const result = state as { readonly success: unknown; readonly value?: unknown };
+    return result.success === true
+      ? { present: true, value: result.value }
+      : { present: false, value: undefined };
+  }
+  return { present: state !== undefined, value: state };
+}
+
+function dependencySatisfied(
+  condition: OptionDependencyCondition,
+  state: Record<string | symbol, unknown>,
+  keyForName: ReadonlyMap<string, string | symbol>,
+): boolean {
+  if (typeof condition === "string") {
+    return dependencySatisfied({ option: condition }, state, keyForName);
+  }
+  if ("option" in condition && condition.option !== undefined) {
+    const key = keyForName.get(condition.option);
+    if (key === undefined) return false;
+    const optionState = unwrapOptionState(state[key]);
+    if (!optionState.present) return false;
+    return "value" in condition
+      ? Object.is(optionState.value, condition.value)
+      : Boolean(optionState.value);
+  }
+  const allOf = condition.allOf;
+  const anyOf = condition.anyOf;
+  return (allOf === undefined || allOf.every((item) =>
+    dependencySatisfied(item, state, keyForName)
+  )) && (anyOf === undefined || anyOf.some((item) =>
+    dependencySatisfied(item, state, keyForName)
+  ));
+}
+
+function dependencyNames(condition: OptionDependencyCondition): readonly string[] {
+  if (typeof condition === "string") return [condition];
+  if (condition.option !== undefined) return [condition.option];
+  return [...(condition.allOf ?? []).flatMap(dependencyNames), ...(condition.anyOf ?? []).flatMap(dependencyNames)];
+}
